import (
	"fmt"
	"math"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a new VM for each execution to ensure isolation
	vm := goja.New()

	// Set up security restrictions
	setupVMSecurity(vm)

	// Inject all order fields as global variables in the VM
	for key, value := range order {
		// Sanitize key to prevent prototype pollution
		if key == "__proto__" || key == "constructor" || key == "prototype" {
			continue
		}
		vm.Set(key, value)
	}

	// Also set the entire order object as a global variable for script access
	vm.Set("order", order)

	// Execute the script with timeout to prevent infinite loops
	done := make(chan bool, 1)
	var result goja.Value
	var err error

	go func() {
		defer func() {
			if r := recover(); r != nil {
				err = fmt.Errorf("script panic: %v", r)
			}
			done <- true
		}()

		result, err = vm.RunString(script)
	}()

	// Wait for execution with timeout
	select {
	case <-done:
		// Script completed
	case <-time.After(2 * time.Second): // 2 second timeout
		return 0.0, fmt.Errorf("script execution timeout")
	}

	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	discount, err := convertToFloat64(result)
	if err != nil {
		return 0.0, err
	}

	// Validate discount range
	if math.IsNaN(discount) || math.IsInf(discount, 0) {
		return 0.0, fmt.Errorf("invalid discount value: %f", discount)
	}

	// Ensure discount is non-negative and reasonable
	if discount < 0 {
		return 0.0, fmt.Errorf("discount cannot be negative: %f", discount)
	}

	// Cap discount at 100% (or any reasonable maximum)
	if discount > 10000 { // Assuming discount is in percentage or reasonable units
		return 0.0, fmt.Errorf("discount too large: %f", discount)
	}

	return discount, nil
}

// setupVMSecurity configures the VM with security restrictions
func setupVMSecurity(vm *goja.Runtime) {
	// Remove dangerous built-in objects
	vm.Set("require", nil)
	vm.Set("eval", nil)
	vm.Set("Function", nil)

	// Limit access to potentially dangerous objects
	vm.Set("console", nil)
	vm.Set("process", nil)
	vm.Set("global", nil)

	// Override potentially dangerous methods on Object
	objProto := vm.Get("Object").ToObject(vm).Get("prototype")
	if objProto != nil {
		objProtoObj := objProto.ToObject(vm)
		objProtoObj.Set("__defineGetter__", nil)
		objProtoObj.Set("__defineSetter__", nil)
		objProtoObj.Set("__lookupGetter__", nil)
		objProtoObj.Set("__lookupSetter__", nil)
	}
}

// convertToFloat64 safely converts a JavaScript value to float64
func convertToFloat64(value goja.Value) (float64, error) {
	exported := value.Export()

	switch v := exported.(type) {
	case float64:
		return v, nil
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case int64:
		return float64(v), nil
	case float32:
		return float64(v), nil
	case uint:
		return float64(v), nil
	case uint32:
		return float64(v), nil
	case uint64:
		return float64(v), nil
	case bool:
		if v {
			return 1.0, nil
		}
		return 0.0, nil
	case string:
		// Try to parse string as number
		var f float64
		_, scanErr := fmt.Sscanf(v, "%f", &f)
		if scanErr != nil {
			return 0.0, fmt.Errorf("cannot convert string '%s' to number", v)
		}
		return f, nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}
}

