	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Create a global 'order' object in the VM
	orderObj := vm.NewObject()
	for key, value := range order {
		err := orderObj.Set(key, value)
		if err != nil {
			return 0.0, fmt.Errorf("failed to set order field '%s': %w", key, err)
		}
	}

	// Set the 'order' global variable
	err := vm.Set("order", orderObj)
	if err != nil {
		return 0.0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Add timeout protection to prevent infinite loops
	done := make(chan bool, 1)
	var result goja.Value
	var execErr error

	go func() {
		defer func() {
			if r := recover(); r != nil {
				execErr = fmt.Errorf("script panic: %v", r)
			}
			done <- true
		}()

		// Execute the script
		result, execErr = vm.RunString(script)
	}()

	// Wait for execution with timeout
	select {
	case <-done:
		// Script completed
	case <-time.After(5 * time.Second):
		return 0.0, fmt.Errorf("script execution timeout - possible infinite loop")
	}

	if execErr != nil {
		return 0.0, fmt.Errorf("script execution error: %w", execErr)
	}

	// Convert result to float64
	var discount float64

	// First try to get the value as float64 directly
	if err := vm.ExportTo(result, &discount); err == nil {
		return discount, nil
	}

	// If direct export fails, try type conversion
	exported := result.Export()
	switch v := exported.(type) {
	case float64:
		discount = v
	case int:
		discount = float64(v)
	case int32:
		discount = float64(v)
	case int64:
		discount = float64(v)
	case float32:
		discount = float64(v)
	case uint:
		discount = float64(v)
	case uint32:
		discount = float64(v)
	case uint64:
		discount = float64(v)
	case bool:
		if v {
			discount = 1.0
		} else {
			discount = 0.0
		}
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}

	return discount, nil
}

